<script>
  var _paq = window._paq = window._paq || [];
  /* tracker methods like "setCustomDimension" should be called before "trackPageView" */
  _paq.push(['appendToTrackingUrl', 'recMode=2']);
_paq.push([ function () {
  var userAgentSubstrings = ["GPTBot","ChatGPT-User","MistralAI-User","Gemini-Deep-Research","Claude-User","Perplexity-User","GoogleAgent","Devin","NovaAct","Google-Extended","Google-CloudVertexBot"];
  for (var i = 0; i < userAgentSubstrings.length; ++i) {
  	var isAiBotUserAgent = navigator.userAgent.toLowerCase().indexOf(userAgentSubstrings[i].toLowerCase()) !== -1;
  	if (isAiBotUserAgent) {
      var path = this.getCookiePath();
      var domain = this.getCookieDomain();
      var sameSite = 'Lax';
      document.cookie = 'matomo_has_js=1;path=' +
      	(path || '/') +
      	(domain ? ';domain=' + domain : '') +
		';SameSite=' + sameSite
		;
  	  return;
  	}
  }
} ]);
_paq.push(['trackPageView']);
_paq.push(['trackAllContentImpressions']);
  _paq.push(['enableLinkTracking']);
  (function() {
    var u="//matomo.aikido-marseille-makoto.fr/";
